// ===== from compat/boost/program_options.hpp =====
// Shim for the subset of hrx::program_options used by XclBinUtilMain:
// options_description + add_options() fluent interface, value<T>()/bool_switch(),
// command_line_parser().options().positional().run(), store(), notify(),
// variables_map::count(), and operator<< help printing.

namespace hrx {
namespace program_options {

class error : public std::runtime_error {
public: explicit error(const std::string& w) : std::runtime_error(w) {}
};

// ---- value semantics ----
class value_semantic {
public:
  bool multi = false;
  bool boolSwitch = false;
  bool hasImplicit = false;
  bool hasDefault = false;
  std::string implicitVal;
  std::string defaultVal;
  std::function<void(const std::vector<std::string>&)> assign;
  std::function<void()> applyDefault;

  value_semantic* multitoken() { multi = true; return this; }
  value_semantic* default_value(const std::string& v) { hasDefault = true; defaultVal = v; return this; }
  value_semantic* implicit_value(const std::string& v) { hasImplicit = true; implicitVal = v; return this; }
};

namespace detail {
inline void assignScalar(std::string* store, const std::string& v) { *store = v; }
template <typename T>
inline void assignScalar(T* store, const std::string& v) { std::istringstream(v) >> *store; }
}

template <typename T>
value_semantic* value(T* store) {
  auto* vs = new value_semantic();
  if constexpr (std::is_same_v<T, std::vector<std::string>>) {
    vs->assign = [store](const std::vector<std::string>& toks) {
      for (auto& t : toks) store->push_back(t);
    };
  } else {
    vs->assign = [store, vs](const std::vector<std::string>& toks) {
      if (!toks.empty()) detail::assignScalar(store, toks.back());
      else if (vs->hasImplicit) detail::assignScalar(store, vs->implicitVal);
    };
    vs->applyDefault = [store, vs]() {
      if (vs->hasDefault) detail::assignScalar(store, vs->defaultVal);
    };
  }
  return vs;
}

inline value_semantic* bool_switch(bool* store) {
  auto* vs = new value_semantic();
  vs->boolSwitch = true;
  *store = false;
  vs->assign = [store](const std::vector<std::string>&) { *store = true; };
  return vs;
}

// ---- options_description ----
struct option_def {
  std::string longName;
  std::string shortName;
  std::string description;
  std::shared_ptr<value_semantic> sem;
};

class options_description;

struct add_options_proxy {
  options_description* od;
  add_options_proxy& operator()(const char* spec, value_semantic* vs, const char* desc = "");
  add_options_proxy& operator()(const char* spec, const char* desc);
};

class options_description {
public:
  explicit options_description(const std::string& caption = "") : m_caption(caption) {}
  add_options_proxy add_options() { return add_options_proxy{this}; }
  options_description& add(const options_description& other) {
    for (auto& o : other.m_opts) m_opts.push_back(o);
    return *this;
  }
  const std::vector<option_def>& options() const { return m_opts; }
  std::vector<option_def>& options() { return m_opts; }

  friend std::ostream& operator<<(std::ostream& os, const options_description& od) {
    if (!od.m_caption.empty()) os << od.m_caption << ":\n";
    for (auto& o : od.m_opts) {
      std::string n = "  --" + o.longName;
      if (!o.shortName.empty()) n += " [ -" + o.shortName + " ]";
      os << n;
      if (n.size() < 34) os << std::string(34 - n.size(), ' '); else os << "  ";
      os << o.description << "\n";
    }
    return os;
  }

  std::string m_caption;
  std::vector<option_def> m_opts;
};

inline void splitSpec(const std::string& spec, std::string& lng, std::string& shrt) {
  auto comma = spec.find(',');
  if (comma == std::string::npos) { lng = spec; shrt.clear(); }
  else { lng = spec.substr(0, comma); shrt = spec.substr(comma + 1); }
}

inline add_options_proxy& add_options_proxy::operator()(const char* spec, value_semantic* vs, const char* desc) {
  option_def od;
  splitSpec(spec, od.longName, od.shortName);
  od.description = desc ? desc : "";
  od.sem.reset(vs);
  this->od->m_opts.push_back(od);
  return *this;
}
inline add_options_proxy& add_options_proxy::operator()(const char* spec, const char* desc) {
  return (*this)(spec, bool_switch(new bool(false)), desc);
}

// ---- positional ----
class positional_options_description {
public:
  positional_options_description& add(const char*, int) { return *this; }
};

// ---- parsed result ----
struct parsed_options {
  const options_description* desc = nullptr;
  std::map<std::string, std::vector<std::string>> present;  // longName -> tokens
};

class command_line_parser {
public:
  command_line_parser(int argc, const char* const* argv) {
    for (int i = 1; i < argc; ++i) m_args.push_back(argv[i]);
  }
  command_line_parser& options(const options_description& d) { m_desc = &d; return *this; }
  command_line_parser& positional(const positional_options_description&) { return *this; }

  parsed_options run() {
    parsed_options out;
    out.desc = m_desc;
    // build lookup
    std::map<std::string, const option_def*> byLong, byShort;
    for (auto& o : m_desc->options()) {
      byLong[o.longName] = &o;
      if (!o.shortName.empty()) byShort[o.shortName] = &o;
    }
    size_t i = 0;
    while (i < m_args.size()) {
      std::string tok = m_args[i++];
      const option_def* opt = nullptr;
      std::string inlineVal; bool haveInline = false;
      if (tok.rfind("--", 0) == 0) {
        std::string name = tok.substr(2);
        auto eq = name.find('=');
        if (eq != std::string::npos) { inlineVal = name.substr(eq + 1); name = name.substr(0, eq); haveInline = true; }
        auto it = byLong.find(name);
        if (it == byLong.end()) throw error("unrecognised option '--" + name + "'");
        opt = it->second;
      } else if (tok.size() >= 2 && tok[0] == '-') {
        std::string s(1, tok[1]);
        if (tok.size() > 2) { inlineVal = tok.substr(2); haveInline = true; }
        auto it = byShort.find(s);
        if (it == byShort.end()) throw error("unrecognised option '-" + s + "'");
        opt = it->second;
      } else {
        continue;  // positional: ignored
      }
      auto& slot = out.present[opt->longName];
      if (opt->sem && opt->sem->boolSwitch) {
        slot.push_back("true");
        continue;
      }
      if (haveInline) { slot.push_back(inlineVal); continue; }
      // consume following non-option token(s)
      bool consumedAny = false;
      while (i < m_args.size()) {
        const std::string& nxt = m_args[i];
        if (nxt.size() >= 1 && nxt[0] == '-' && !(nxt.size() >= 2 && std::isdigit((unsigned char)nxt[1]))) break;
        slot.push_back(nxt); ++i; consumedAny = true;
        if (!(opt->sem && opt->sem->multi)) break;  // single value
      }
      (void)consumedAny;
    }
    return out;
  }

private:
  std::vector<std::string> m_args;
  const options_description* m_desc = nullptr;
};

// ---- variables_map ----
class variables_map {
public:
  std::map<std::string, std::vector<std::string>> present;
  const options_description* desc = nullptr;
  size_t count(const std::string& name) const {
    auto it = present.find(name);
    return it == present.end() ? 0 : 1;
  }
};

inline void store(const parsed_options& parsed, variables_map& vm) {
  vm.present = parsed.present;
  vm.desc = parsed.desc;
}

inline void notify(variables_map& vm) {
  if (!vm.desc) return;
  for (auto& o : vm.desc->options()) {
    auto it = vm.present.find(o.longName);
    if (it != vm.present.end()) {
      if (o.sem && o.sem->assign) o.sem->assign(it->second);
    } else if (o.sem && o.sem->applyDefault) {
      o.sem->applyDefault();
    }
  }
}

} // namespace program_options
} // namespace hrx
